function LODIndicator({ lod, zoom }) {
  const intentMap = { MACRO: 'warning', MESO: 'primary', MICRO: 'success' };
  const labelMap = { MACRO: 'Strategic', MESO: 'Tactical', MICRO: 'Operational' };

